const item = items[0];
const payload = item.json || {};

const normalize = (value) => String(value || '').trim().toUpperCase();
const escapeReason = (value) => String(value || '').trim();
const toArray = (value) => {
  if (Array.isArray(value)) return value;
  if (!value) return [];
  return String(value)
    .split(/\n|,/) 
    .map((entry) => entry.replace(/^-\s*/, '').trim())
    .filter(Boolean);
};

const rank = (value, map, label) => {
  if (!value) return 0;
  if (!(value in map)) {
    throw new Error(`Unknown ${label}: ${value}`);
  }
  return map[value];
};

const decisionRank = {
  INFORMATIONAL: 1,
  ADVISORY: 2,
  OPERATIONAL: 3,
  TRANSACTIONAL: 4,
  STRATEGIC: 5,
};
const dataRank = {
  PUBLIC: 1,
  INTERNAL: 2,
  CONFIDENTIAL: 3,
  RESTRICTED: 4,
};
const commRank = {
  INTERNAL_ONLY: 1,
  CLIENT_ROUTINE: 2,
  ADVISORY: 3,
  PARTNER: 4,
  PUBLIC: 5,
  LEADERSHIP: 6,
};
const systemRank = {
  READ_ONLY: 1,
  WRITE_LIMITED: 2,
  WRITE_BROAD: 3,
  ADMIN: 4,
};

const allowed = {
  decision: normalize('{{decision_level}}'),
  data: normalize('{{data_ceiling}}'),
  comm: normalize('{{comm_scope}}'),
  system: normalize('{{system_access}}'),
};

const requested = {
  decision: normalize(payload.action_decision_level || payload.decision_level || allowed.decision),
  data: normalize(payload.data_classification || payload.data_level || allowed.data),
  comm: normalize(payload.recipient_scope || payload.communication_scope || allowed.comm),
  system: normalize(payload.requested_system_access || payload.system_access || allowed.system),
};

if (rank(requested.decision, decisionRank, 'decision level') > rank(allowed.decision, decisionRank, 'decision level')) {
  throw new Error(`Authority violation: requested decision level ${requested.decision} exceeds ${allowed.decision}`);
}
if (rank(requested.data, dataRank, 'data level') > rank(allowed.data, dataRank, 'data level')) {
  throw new Error(`Authority violation: requested data access ${requested.data} exceeds ${allowed.data}`);
}
if (rank(requested.comm, commRank, 'communication scope') > rank(allowed.comm, commRank, 'communication scope')) {
  throw new Error(`Authority violation: requested communication scope ${requested.comm} exceeds ${allowed.comm}`);
}
if (rank(requested.system, systemRank, 'system access') > rank(allowed.system, systemRank, 'system access')) {
  throw new Error(`Authority violation: requested system access ${requested.system} exceeds ${allowed.system}`);
}

const triggers = toArray(`{{escalation_triggers}}`).map((entry) => entry.toLowerCase());
const riskFlags = toArray(payload.risk_flags).map((entry) => entry.toLowerCase());
const stakeholders = toArray(payload.stakeholders).map((entry) => entry.toLowerCase());
const customEscalationReason = escapeReason(payload.escalation_reason);

let requiresEscalation = false;
let escalationReason = customEscalationReason || '';

if (triggers.includes('scope boundary') && payload.out_of_scope) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation trigger matched: scope boundary';
}
if (triggers.includes('risk or sensitivity') && riskFlags.length > 0) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation trigger matched: risk or sensitivity';
}
if (triggers.includes('ambiguity') && payload.ambiguous) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation trigger matched: ambiguity';
}
if (triggers.includes('key stakeholder') && stakeholders.length > 0) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation trigger matched: key stakeholder';
}
if (triggers.includes('authority ceiling') && payload.near_authority_limit) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation trigger matched: authority ceiling';
}
if (payload.force_escalation === true) {
  requiresEscalation = true;
  escalationReason = escalationReason || 'Escalation forced by upstream system';
}

item.json.requires_escalation = requiresEscalation;
item.json.escalation_reason = escalationReason || 'Human review required by governance policy';
item.json.allowed_authority = allowed;
item.json.requested_authority = requested;

return items;
